class Solution:
    def minimumRemoval(self, beans):
        n = len(beans)
        total = sum(beans)
        best_removal = total
        candidates = set(beans) | {0}
        for c in candidates:
            removal = 0
            for b in beans:
                if b < c:
                    removal += b
                else:
                    removal += b - c
            if removal < best_removal:
                best_removal = removal
        return best_removal

