class Solution:
    def minimumRemoval(self, beans):
        beans = sorted(beans)
        n = len(beans)
        total = sum(beans)
        best_keep = 0
        for i in range(n):
            keep = beans[i] * (n - i)
            if keep > best_keep:
                best_keep = keep
        return total - best_keep

