var minimumRemoval = function(beans) {
    const sorted = [...beans].sort((a, b) => a - b);
    const n = sorted.length;
    let total = 0;
    for (const b of sorted) total += b;
    let bestKeep = 0;
    for (let i = 0; i < n; i++) {
        const keep = sorted[i] * (n - i);
        if (keep > bestKeep) bestKeep = keep;
    }
    return total - bestKeep;
};
